#include <initializer_list>

int sum(std::initializer_list<int> values) {
    int total = 0;
    for (int v : values) {
        total += v;
    }
    return total;
}

int main() {
    return sum({1, 2, 3, 4});
}

#include <initializer_list>

int first(std::initializer_list<int> values) {
    return values.size() > 0 ? *values.begin() : 0;
}

